//! Tests for the LLM response caching layer.\n//!\n//! Covers:\n//! - Cache key generation (deterministic, case-normalized, route-scoped)\n//! - Advisory lock ID generation (deterministic, positive, route-scoped)\n//! - Canonical JSON serialization (sorted keys, compact)\n//! - Cache route constants and TTL\n//! - Concurrency semantics via advisory locks (tested without DB)\n\nuse klass_gateway::cache::{\n    build_cache_key, build_lock_id, to_canonical_json_string, CacheRoute, LlmCacheRepo,\n};\nuse std::sync::Arc;\nuse std::time::Duration;\n\n// ═════════════════════════════════════════════════════════════════════════════\n// 1. Cache Key Generation\n// ═════════════════════════════════════════════════════════════════════════════\n\n#[test]\nfn test_cache_key_is_64_char_hex() {\n    let input = serde_json::json!({\"teacher_prompt\": \"Buatkan materi\"});\n    let key = build_cache_key(\n        CacheRoute::Interpret,\n        \"tencent\",\n        \"hy3:free\",\n        \"media_prompt_interpretation\",\n        \"Interpret the prompt\",\n        &input,\n    );\n    assert_eq!(key.len(), 64, \"SHA-256 hex digest must be 64 characters\");\n    assert!(\n        key.chars().all(|c| c.is_ascii_hexdigit()),\n        \"key must be hex only\"\n    );\n}\n\n#[test]\nfn test_cache_key_deterministic() {\n    let input = serde_json::json!({\"teacher_prompt\": \"Buatkan materi pecahan\"});\n    let key1 = build_cache_key(\n        CacheRoute::Interpret,\n        \"tencent\",\n        \"hy3:free\",\n        \"media_prompt_interpretation\",\n        \"Interpret the following prompt\",\n        &input,\n    );\n    let key2 = build_cache_key(\n        CacheRoute::Interpret,\n        \"tencent\",\n        \"hy3:free\",\n        \"media_prompt_interpretation\",\n        \"Interpret the following prompt\",\n        &input,\n    );\n    assert_eq!(key1, key2, \"same inputs must produce same key\");\n}\n\n#[test]\nfn test_cache_key_different_routes_differ() {\n    let input = serde_json::json!({\"title\": \"test\"});\n    let key_interpret = build_cache_key(\n        CacheRoute::Interpret, \"p\", \"m\", \"t\", \"i\", &input,\n    );\n    let key_respond = build_cache_key(\n        CacheRoute::Respond, \"p\", \"m\", \"t\", \"i\", &input,\n    );\n    assert_ne!(key_interpret, key_respond, \"different routes must differ\");\n}\n\n#[test]\nfn test_cache_key_input_field_order_independent() {\n    let input1 = serde_json::json!({\"a\": 1, \"b\": 2});\n    let input2 = serde_json::json!({\"b\": 2, \"a\": 1});\n    let key1 = build_cache_key(\n        CacheRoute::Interpret, \"dp\", \"m\", \"t\", \"i\", &input1,\n    );\n    let key2 = build_cache_key(\n        CacheRoute::Interpret, \"dp\", \"m\", \"t\", \"i\", &input2,\n    );\n    assert_eq!(key1, key2, \"keys must be independent of JSON field order\");\n}\n\n#[test]\nfn test_cache_key_normalizes_provider_case() {\n    let input = serde_json::json!({\"prompt\": \"hello\"});\n    let key_upper = build_cache_key(\n        CacheRoute::Interpret, \"tencent\", \"m\", \"t\", \"i\", &input,\n    );\n    let key_lower = build_cache_key(\n        CacheRoute::Interpret, \"tencent\", \"m\", \"t\", \"i\", &input,\n    );\n    assert_eq!(\n        key_upper, key_lower,\n        \"provider should be case-normalized to lowercase\"\n    );\n}\n\n#[test]\nfn test_cache_key_changes_with_instruction() {\n    let input = serde_json::json!({\"teacher_prompt\": \"test\"});\n    let key1 = build_cache_key(\n        CacheRoute::Interpret, \"p\", \"m\", \"t\", \"instruction A\", &input,\n    );\n    let key2 = build_cache_key(\n        CacheRoute::Interpret, \"p\", \"m\", \"t\", \"instruction B\", &input,\n    );\n    assert_ne!(key1, key2, \"different instructions must produce different keys\");\n}\n\n#[test]\nfn test_cache_key_changes_with_payload() {\n    let input1 = serde_json::json!({\"teacher_prompt\": \"prompt one\"});\n    let input2 = serde_json::json!({\"teacher_prompt\": \"prompt two\"});\n    let key1 = build_cache_key(\n        CacheRoute::Interpret, \"p\", \"m\", \"t\", \"i\", &input1,\n    );\n    let key2 = build_cache_key(\n        CacheRoute::Interpret, \"p\", \"m\", \"t\", \"i\", &input2,\n    );\n    assert_ne!(key1, key2, \"different payloads must produce different keys\");\n}\n\n#[test]\nfn test_cache_key_with_empty_input() {\n    let input = serde_json::json!({});\n    let key = build_cache_key(CacheRoute::Interpret, \"\", \"\", \"\", \"\", &input);\n    assert_eq!(key.len(), 64, \"empty input should still produce a valid key\");\n}\n\n#[test]\nfn test_cache_key_with_nested_input() {\n    let input = serde_json::json!({\n        \"teacher_prompt\": \"hello\",\n        \"subject_context\": {\"name\": \"IPA\", \"slug\": \"ipa\"},\n        \"sub_subject_context\": {\"name\": \"Gaya\", \"slug\": \"gaya\"},\n    });\n    let key = build_cache_key(\n        CacheRoute::Interpret,\n        \"tencent\",\n        \"hy3:free\",\n        \"media_prompt_interpretation\",\n        \"Default instruction\",\n        &input,\n    );\n    assert_eq!(key.len(), 64);\n}\n\n// ═════════════════════════════════════════════════════════════════════════════\n// 2. Advisory Lock ID\n// ═════════════════════════════════════════════════════════════════════════════\n\n#[test]\nfn test_lock_id_is_positive() {\n    let id = build_lock_id(CacheRoute::Interpret, \"test-key\");\n    assert!(id > 0, \"PG advisory lock ID must be positive, got {}\", id);\n}\n\n#[test]\nfn test_lock_id_deterministic() {\n    let id1 = build_lock_id(CacheRoute::Interpret, \"same-key\");\n    let id2 = build_lock_id(CacheRoute::Interpret, \"same-key\");\n    assert_eq!(id1, id2);\n}\n\n#[test]\nfn test_lock_id_different_routes_differ() {\n    let id1 = build_lock_id(CacheRoute::Interpret, \"key\");\n    let id2 = build_lock_id(CacheRoute::Respond, \"key\");\n    assert_ne!(id1, id2, \"different routes must differ\");\n}\n\n#[test]\nfn test_lock_id_different_keys_differ() {\n    let id1 = build_lock_id(CacheRoute::Interpret, \"key-1\");\n    let id2 = build_lock_id(CacheRoute::Interpret, \"key-2\");\n    assert_ne!(id1, id2);\n}\n\n#[test]\nfn test_lock_id_with_spaces() {\n    let id = build_lock_id(CacheRoute::Interpret, \"  key with spaces  \");\n    assert!(id > 0);\n}\n\n// ═════════════════════════════════════════════════════════════════════════════\n// 3. Canonical JSON Serialization\n// ═════════════════════════════════════════════════════════════════════════════\n\n#[test]\nfn test_canonical_json_sorts_keys() {\n    let doc = serde_json::json!({\"z\": 1, \"m\": 2, \"a\": 3});\n    let s = to_canonical_json_string(&doc);\n    assert_eq!(s, \"{\\\"a\\\":3,\\\"m\\\":2,\\\"z\\\":1}\");\n}\n\n#[test]\nfn test_canonical_json_field_order_independent() {\n    let doc1 = serde_json::json!({\"b\": 1, \"a\": 2});\n    let doc2 = serde_json::json!({\"a\": 2, \"b\": 1});\n    assert_eq!(\n        to_canonical_json_string(&doc1),\n        to_canonical_json_string(&doc2)\n    );\n}\n\n#[test]\nfn test_canonical_json_nested_objects() {\n    let doc = serde_json::json!({\"b\": {\"y\": 1, \"x\": 2}, \"a\": 3});\n    assert_eq!(\n        to_canonical_json_string(&doc),\n        \"{\\\"a\\\":3,\\\"b\\\":{\\\"x\\\":2,\\\"y\\\":1}}\"\n    );\n}\n\n#[test]\nfn test_canonical_json_array_preserves_order() {\n    let doc = serde_json::json!([\"b\", \"a\", \"c\"]);\n    assert_eq!(\n        to_canonical_json_string(&doc),\n        \"[\\\"b\\\",\\\"a\\\",\\\"c\\\"]\"\n    );\n}\n\n#[test]\nfn test_canonical_json_primitives() {\n    assert_eq!(to_canonical_json_string(&serde_json::json!(\"hello\")), \"\\\"hello\\\"\");\n    assert_eq!(to_canonical_json_string(&serde_json::json!(42)), \"42\");\n    assert_eq!(to_canonical_json_string(&serde_json::json!(true)), \"true\");\n    assert_eq!(to_canonical_json_string(&serde_json::json!(null)), \"null\");\n}\n\n#[test]\nfn test_canonical_json_compact_format() {\n    // Verify no spaces between keys and values\n    let doc = serde_json::json!({\"a\": 1});\n    let s = to_canonical_json_string(&doc);\n    // Python json.dumps(separators=(\",\", \":\")) produces {\"a\":1}\n    assert_eq!(s, \"{\\\"a\\\":1}\");\n    assert!(!s.contains(' '), \"canonical JSON must not contain spaces\");\n}\n\n// ═════════════════════════════════════════════════════════════════════════════\n// 4. Cache Route\n// ═════════════════════════════════════════════════════════════════════════════\n\n#[test]\nfn test_cache_route_as_str() {\n    assert_eq!(CacheRoute::Interpret.as_str(), \"interpret\");\n    assert_eq!(CacheRoute::Respond.as_str(), \"respond\");\n}\n\n#[test]\nfn test_cache_route_default_ttl() {\n    assert_eq!(CacheRoute::Interpret.default_ttl_seconds(), 3600);\n    assert_eq!(CacheRoute::Respond.default_ttl_seconds(), 86400);\n}\n\n#[test]\nfn test_cache_route_interpret_ttl_is_one_hour() {\n    assert_eq!(CacheRoute::Interpret.default_ttl_seconds(), 3600);\n}\n\n#[test]\nfn test_cache_route_respond_ttl_is_one_day() {\n    assert_eq!(CacheRoute::Respond.default_ttl_seconds(), 86400);\n}\n\n#[test]\nfn test_cache_route_equality() {\n    assert_eq!(CacheRoute::Interpret, CacheRoute::Interpret);\n    assert_ne!(CacheRoute::Interpret, CacheRoute::Respond);\n}\n\n// ═════════════════════════════════════════════════════════════════════════════\n// 5. Concurrency Simulation (lock semantics without DB)\n// ═════════════════════════════════════════════════════════════════════════════\n\n#[test]\nfn test_lock_id_collision_probability() {\n    // Generate 1000 different keys and verify no lock ID collisions\n    // (blake2 64-bit is astronomically safe, but this is a sanity check)\n    let mut ids = std::collections::HashSet::new();\n    for i in 0..1000 {\n        let key = format!(\"test-key-{}\", i);\n        let id = build_lock_id(CacheRoute::Interpret, &key);\n        assert!(\n            ids.insert(id),\n            \"collision on key {} with id {}\",\n            key, id\n        );\n    }\n}\n\n#[test]\nfn test_cache_key_long_payload_stability() {\n    // Very long teacher prompt should still produce a consistent key\n    let long_prompt = \"Buatkan \".repeat(200); // ~1600 chars\n    let input = serde_json::json!({\"teacher_prompt\": long_prompt});\n    let key1 = build_cache_key(\n        CacheRoute::Interpret, \"dp\", \"m\", \"t\", \"i\", &input,\n    );\n    let key2 = build_cache_key(\n        CacheRoute::Interpret, \"dp\", \"m\", \"t\", \"i\", &input,\n    );\n    assert_eq!(key1, key2, \"long payloads must be deterministic\");\n    assert_eq!(key1.len(), 64);\n}\n\n/// Simulate an anti-stampede lock using a simple Mutex.\n/// This tests that only one \"provider\" can proceed while others wait.\n#[tokio::test]\nasync fn test_concurrent_anti_stampede_simulation() {\n    use tokio::sync::Mutex as TokioMutex;\n    use std::sync::atomic::{AtomicU32, Ordering};\n\n    let provider_call_count = Arc::new(AtomicU32::new(0));\n    let lock = Arc::new(TokioMutex::new(()));\n\n    let mut handles = vec![];\n    for _ in 0..10 {\n        let count = Arc::clone(&provider_call_count);\n        let lock = Arc::clone(&lock);\n        handles.push(tokio::spawn(async move {\n            // Try to acquire the \"advisory lock\"\n            let _guard = lock.lock().await;\n            // Only one task should increment at a time\n            count.fetch_add(1, Ordering::SeqCst);\n            tokio::time::sleep(Duration::from_millis(5)).await;\n        }));\n    }\n\n    for h in handles {\n        h.await.unwrap();\n    }\n\n    let total = provider_call_count.load(Ordering::SeqCst);\n    // All 10 tasks should have completed (they just run serially)\n    assert_eq!(total, 10, \"all 10 tasks should have run\");\n}\n\n/// Simulate a race where two tasks compete for the same lock.\n#[tokio::test]\nasync fn test_lock_mutex_exclusion() {\n    use tokio::sync::Mutex as TokioMutex;\n\n    let lock = Arc::new(TokioMutex::new(false));\n    let lock2 = Arc::clone(&lock);\n\n    let task1 = tokio::spawn(async move {\n        let _guard = lock.lock().await;\n        tokio::time::sleep(Duration::from_millis(20)).await;\n    });\n\n    let task2 = tokio::spawn(async move {\n        // Slight delay to ensure task1 acquires first\n        tokio::time::sleep(Duration::from_millis(5)).await;\n        let _guard = lock2.try_lock();\n        // try_lock should return None because task1 holds the lock\n        assert!(\n            _guard.is_none(),\n            \"second task should not acquire lock while first holds it\"\n        );\n    });\n\n    let _ = tokio::join!(task1, task2);\n}\n\n// ═════════════════════════════════════════════════════════════════════════════\n// 6. LlmCacheRepo Construction\n// ═════════════════════════════════════════════════════════════════════════════\n\n/// Verify that LlmCacheRepo can be constructed (requires DB pool, but we\n/// can at least test that the new() function accepts a PgPool).\n/// This test is architecture-level: it ensures the type is instantiable.\n#[test]\nfn test_cache_repo_type_exists() {\n    // We can't create a PgPool here (no DB), but we can verify the type\n    // compiles and has the expected public API by referencing its signature\n    fn _assert_send_sync<T: Send + Sync>() {}\n    _assert_send_sync::<LlmCacheRepo>();\n}\n